@MainActor
struct HTMLPreviewCoordinatorTests {

    // MARK: Happy Path

    @Test func initialCapturedSelectionIsEmpty() {
        let c = HTMLPreviewCoordinator(router: nil)
        #expect(c.capturedSelection.isEmpty)
    }

    @Test func initialLinkNavigationIsEnabled() {
        let c = HTMLPreviewCoordinator(router: nil)
        #expect(c.isLinkNavigationEnabled == true)
    }

    @Test func initialCurrentBaseURLIsNil() {
        let c = HTMLPreviewCoordinator(router: nil)
        #expect(c.currentBaseURL == nil)
    }

    @Test func initialFullSessionTextIsEmpty() {
        let c = HTMLPreviewCoordinator(router: nil)
        #expect(c.fullSessionText.isEmpty)
    }

    // MARK: State Transitions

    @Test func capturedSelectionCanBeUpdated() {
        let c = HTMLPreviewCoordinator(router: nil)
        c.capturedSelection = "hello world"
        #expect(c.capturedSelection == "hello world")
    }

    @Test func capturedSelectionCanBeCleared() {
        let c = HTMLPreviewCoordinator(router: nil)
        c.capturedSelection = "some text"
        c.capturedSelection = ""
        #expect(c.capturedSelection.isEmpty)
    }

    @Test func linkNavigationCanBeDisabled() {
        let c = HTMLPreviewCoordinator(router: nil)
        c.isLinkNavigationEnabled = false
        #expect(c.isLinkNavigationEnabled == false)
    }

    @Test func currentBaseURLCanBeSet() {
        let c = HTMLPreviewCoordinator(router: nil)
        let url = URL(string: "file:///Users/test/site/")!
        c.currentBaseURL = url
        #expect(c.currentBaseURL == url)
    }

    @Test func currentBaseURLCanBeCleared() {
        let c = HTMLPreviewCoordinator(router: nil)
        c.currentBaseURL = URL(string: "file:///Users/test/")!
        c.currentBaseURL = nil
        #expect(c.currentBaseURL == nil)
    }

    @Test func fullSessionTextCanBeSet() {
        let c = HTMLPreviewCoordinator(router: nil)
        c.fullSessionText = "<html><body>Hello</body></html>"
        #expect(c.fullSessionText == "<html><body>Hello</body></html>")
    }

    @Test func onLoadErrorCallbackIsInvoked() {
        let c = HTMLPreviewCoordinator(router: nil)
        var received: String?
        c.onLoadError = { received = $0 }
        c.onLoadError?("connection refused")
        #expect(received == "connection refused")
    }

    @Test func isShowingPlaceholderDefaultsToFalse() {
        let c = HTMLPreviewCoordinator(router: nil)
        #expect(c.isShowingPlaceholder == false)
    }
}

// MARK: - splitHTML

@MainActor
struct SplitHTMLTests {

    /// ISS-086: a closed-range subscript trapped when `</head>` ended the string.
    /// The half-open form must split head-only HTML without crashing.
    @Test func headOnlyHTMLDoesNotCrash() {
        let (head, body) = HTMLPreviewCoordinator.splitHTML("<html><head></head>")
        #expect(head == "<html><head></head>")
        #expect(body.isEmpty)
    }

    @Test func headAndEmptyBodySplitsCorrectly() {
        let (head, body) = HTMLPreviewCoordinator.splitHTML("<html><head></head><body></body>")
        #expect(head == "<html><head></head>")
        #expect(body.isEmpty)
    }

    @Test func headAndBodyContentSplitsCorrectly() {
        let (head, body) = HTMLPreviewCoordinator.splitHTML(
            "<html><head><title>x</title></head><body><p>hi</p></body></html>")
        #expect(head == "<html><head><title>x</title></head>")
        #expect(body == "<p>hi</p>")
    }

    @Test func noHeadReturnsWholeStringAsBody() {
        let (head, body) = HTMLPreviewCoordinator.splitHTML("<p>no head here</p>")
        #expect(head.isEmpty)
        #expect(body == "<p>no head here</p>")
    }
}
